// 計算費用總計、hash、格式化時間
const payload = $input.item.json.body;

const costItems = payload.cost_split || [];
const summary = {
  zeyu:     { name: '哲宇家', owed: 0, paid: 0, remaining: 0, pct: 0 },
  shengmin: { name: '聖閔家', owed: 0, paid: 0, remaining: 0, pct: 0 }
};

for (const item of costItems) {
  summary.zeyu.owed     += parseFloat(item.zeyu_owed     || 0);
  summary.zeyu.paid     += parseFloat(item.zeyu_paid     || 0);
  summary.shengmin.owed += parseFloat(item.shengmin_owed || 0);
  summary.shengmin.paid += parseFloat(item.shengmin_paid || 0);
}

for (const f of Object.values(summary)) {
  f.remaining = Math.round(f.owed - f.paid);
  f.pct = f.owed > 0 ? Math.round(f.paid / f.owed * 1000) / 10 : 0;
}

// 地點 hash：排序後 join
const locationHash = [...(payload.locations || [])].sort().join('|');

// 台北時間
const now = new Date().toLocaleString('zh-TW', {
  timeZone: 'Asia/Taipei',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit'
});

return [{ json: { ...payload, cost_summary: summary, location_hash: locationHash, last_updated: now } }];

const tripData = $('計算衍生資料').item.json;
const cacheResp = $input.item.json;

let cached = { location_hash: '', ai_content: {} };
let cacheSha = null;

if (cacheResp.sha && cacheResp.content) {
  cacheSha = cacheResp.sha;
  try {
    cached = JSON.parse(Buffer.from(cacheResp.content, 'base64').toString('utf-8'));
  } catch(e) {}
}

// 找出沒有 AI 介紹的新地點
const newLocations = (tripData.locations || [])
  .filter(loc => !(loc in (cached.ai_content || {})));

return [{ json: {
  ...tripData,
  cached_ai:    cached.ai_content || {},
  cache_sha:    cacheSha,
  new_locations: newLocations,
  needs_ai:     newLocations.length > 0
} }];

const d = $input.item.json;
const prompt = '請用繁體中文為以下景點各寫一段介紹（每個景點約 150 字，包含簡介、必看亮點、1-2 個實用 tips）。

景點列表：' + d.new_locations.join('、') + '

請以 JSON 格式回覆，格式範例：{ "景點名": { "intro": "介紹內容", "tips": "Tip 內容" } }。只回傳 JSON，不要其他說明文字。';

return [{ json: { ...d, openai_body: { model: 'gpt-4o-mini', max_tokens: 2048, messages: [{ role: 'user', content: prompt }] } } }];

const tripData = $('比對 hash').item.json;
const openaiResp = $input.item.json;

let newAI = {};
try {
  const rawText = openaiResp.choices[0].message.content.trim();
  // 擷取 JSON 區塊（GPT 可能包在 markdown code block）
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) newAI = JSON.parse(match[0]);
} catch(e) {
  console.log('AI parse error:', e.message);
}

return [{ json: {
  ...tripData,
  ai_content: { ...tripData.cached_ai, ...newAI },
  ai_updated: true,
  ai_new_count: Object.keys(newAI).length
} }];

const d = $input.item.json;

// 組合 data.json（供網頁讀取）
const dataJson = {
  trip_name:    d.trip_name,
  trip_id:      d.trip_id,
  date_range:   d.date_range,
  last_updated: d.last_updated,
  locations:    d.locations,
  itinerary:    d.itinerary || [],
  cost_summary: d.cost_summary,
  ai_content:   d.ai_content
};

// 組合 cache.json（供下次比對）
const cacheJson = {
  location_hash: d.location_hash,
  locations:     d.locations,
  ai_content:    d.ai_content,
  updated_at:    d.last_updated
};

return [{ json: {
  ...d,
  data_json_b64:  Buffer.from(JSON.stringify(dataJson, null, 2)).toString('base64'),
  cache_json_b64: Buffer.from(JSON.stringify(cacheJson, null, 2)).toString('base64')
} }];

const d = $('組合 JSON 檔案').item.json;
const shaResp = $input.item.json;

const putBody = {
  message: `sync(${d.trip_id}): ${d.last_updated}${d.ai_updated ? ' [AI updated ' + d.ai_new_count + ' spots]' : ''}`,
  content: d.data_json_b64,
  ...(shaResp.sha ? { sha: shaResp.sha } : {})
};

return [{ json: { ...d, data_put_body: putBody } }];

const d = $('組合 JSON 檔案').item.json;
const shaResp = $input.item.json;

const putBody = {
  message: `cache(${d.trip_id}): update location hash`,
  content: d.cache_json_b64,
  ...(shaResp.sha ? { sha: shaResp.sha } : {})
};

return [{ json: { ...d, cache_put_body: putBody } }];
